CREATE TABLE IF NOT EXISTS `ims_ewei_message_mass_sign` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `openid` varchar(50) DEFAULT NULL, `nickname` varchar(50) DEFAULT NULL, `taskid` int(11) DEFAULT NULL, `status` tinyint(1) DEFAULT NULL, `log` varchar(255) DEFAULT NULL, PRIMARY KEY (`id`), KEY `idx_openid` (`openid`), KEY `idx_taskid` (`taskid`), KEY `idx_status` (`status`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_message_mass_task` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `title` varchar(255) DEFAULT '', `status` tinyint(1) DEFAULT '0', `processnum` int(11) DEFAULT '1', `sendnum` int(11) DEFAULT '0', `messagetype` tinyint(1) DEFAULT '0', `templateid` int(11) DEFAULT '0', `resptitle` varchar(255) DEFAULT NULL, `respthumb` varchar(255) DEFAULT NULL, `respdesc` varchar(255) DEFAULT NULL, `respurl` varchar(255) DEFAULT NULL, `sendlimittype` tinyint(1) DEFAULT '0', `send_openid` text, `send_level` int(11) DEFAULT NULL, `send_group` int(11) DEFAULT NULL, `send_agentlevel` int(11) DEFAULT NULL, `customertype` tinyint(1) DEFAULT '0', `resdesc2` varchar(255) DEFAULT '', `pagecount` int(11) DEFAULT '0', `successnum` int(11) DEFAULT '0', `failnum` int(11) DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_message_mass_template` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `title` varchar(255) DEFAULT '', `template_id` varchar(255) DEFAULT '', `first` text NOT NULL, `firstcolor` varchar(255) DEFAULT '', `data` text NOT NULL, `remark` text NOT NULL, `remarkcolor` varchar(255) DEFAULT '', `url` varchar(255) NOT NULL, `createtime` int(11) DEFAULT '0', `sendtimes` int(11) DEFAULT '0', `sendcount` int(11) DEFAULT '0', `miniprogram` tinyint(1) DEFAULT '0', `appid` varchar(255) DEFAULT '', `pagepath` varchar(255) DEFAULT '', PRIMARY KEY (`id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_advertisement` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `name` varchar(8) DEFAULT NULL, `logo` text, `url` text, `create_time` datetime NOT NULL, PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_chicken` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `openid` varchar(64) DEFAULT NULL, `name` varchar(32) DEFAULT NULL, `portrait` text, `level` int(11) unsigned NOT NULL DEFAULT '0', `experience` int(11) unsigned NOT NULL DEFAULT '0', `accelerate` int(11) unsigned NOT NULL DEFAULT '0', `egg_stock` int(11) unsigned NOT NULL DEFAULT '0', `last_egg_stock` int(11) unsigned NOT NULL DEFAULT '0', `feed_stock` int(11) unsigned NOT NULL DEFAULT '0', `bowl_stock` int(11) unsigned NOT NULL DEFAULT '0', `integral` int(11) unsigned NOT NULL DEFAULT '0', `feeding_time` datetime DEFAULT NULL, `feeding_sum` int(11) unsigned NOT NULL DEFAULT '0', `lay_eggs_eat` int(11) unsigned NOT NULL DEFAULT '0', `lay_eggs_sum` int(11) unsigned NOT NULL DEFAULT '0', `eat_sum` int(11) unsigned NOT NULL DEFAULT '0', `surprised_guard` int(11) unsigned NOT NULL DEFAULT '0', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_configure` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `name` varchar(64) DEFAULT NULL, `url` text, `qrcode` text, `keyword` varchar(64) DEFAULT NULL, `title` text, `logo` text, `describe` text, `public_qrcode` text, `force_follow` enum('1','0') NOT NULL DEFAULT '0', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_egg` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `openid` varchar(64) DEFAULT NULL, `sum` int(11) unsigned NOT NULL DEFAULT '0', `use_sum` int(11) unsigned NOT NULL DEFAULT '0', `status` enum('是','否') NOT NULL DEFAULT '否', `receive` enum('是','否') NOT NULL DEFAULT '否', `use_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_grade` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `level` int(11) unsigned NOT NULL DEFAULT '0', `experience` int(11) unsigned NOT NULL DEFAULT '0', `accelerate` int(11) unsigned NOT NULL DEFAULT '0', `surprised_guard` int(11) unsigned NOT NULL DEFAULT '0', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_indicate` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `image` text, `describe` text, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_integral` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `openid` varchar(64) DEFAULT NULL, `nickname` varchar(64) DEFAULT NULL, `order_id` varchar(128) DEFAULT NULL, `integral` int(11) unsigned NOT NULL DEFAULT '0', `egg` int(11) unsigned NOT NULL DEFAULT '0', `receive` enum('是','否') NOT NULL DEFAULT '否', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_log` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `category` enum('获取优惠券','获取积分','获取鸡蛋','获取饲料','获取道具卡','兑换商品') NOT NULL DEFAULT '获取优惠券', `describe` text, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_market` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `title` varchar(8) DEFAULT NULL, `type` enum('商品','积分') NOT NULL DEFAULT '积分', `value` int(11) unsigned NOT NULL DEFAULT '0', `egg` int(11) unsigned NOT NULL DEFAULT '0', `logo` text, `number` int(11) unsigned NOT NULL DEFAULT '0', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_mood` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `background` text, `logo` text, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_mood_image` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `picture` text, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_notice` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `title` varchar(64) DEFAULT NULL, `content` longtext, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_order` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `openid` varchar(64) DEFAULT NULL, `username` varchar(64) DEFAULT NULL, `market_id` int(11) unsigned NOT NULL DEFAULT '0', `market_title` varchar(64) DEFAULT NULL, `receive` enum('1','0') NOT NULL DEFAULT '0', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_presentation` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `openid` varchar(64) DEFAULT NULL, `content` text, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_prop` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `name` varchar(64) NOT NULL DEFAULT '', `logo` text, `deposit_max` int(11) unsigned NOT NULL DEFAULT '0', `day_use_max` int(11) unsigned NOT NULL DEFAULT '0', `effect` enum('进食加速','新单卡','其它') NOT NULL DEFAULT '其它', `value` text, `get_category` enum('完成任务','积分兑换','购买商品') NOT NULL DEFAULT '完成任务', `get_value` text, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_reply` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `brief_introduce` text, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_seting` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `eat_time` int(11) unsigned NOT NULL DEFAULT '0', `time_steal` int(11) unsigned NOT NULL DEFAULT '0', `steal_eat_time` int(11) unsigned NOT NULL DEFAULT '0', `eat_tips` varchar(64) NOT NULL DEFAULT '', `warehouse` int(11) unsigned NOT NULL DEFAULT '0', `bowl` int(11) unsigned NOT NULL DEFAULT '0', `lay_eggs_eat` int(11) unsigned NOT NULL DEFAULT '0', `lay_eggs_tips` varchar(64) NOT NULL DEFAULT '', `lay_eggs_number_min` int(11) unsigned NOT NULL DEFAULT '0', `lay_eggs_number_max` int(11) unsigned NOT NULL DEFAULT '0', `obtain_feed_max` int(11) unsigned NOT NULL DEFAULT '0', `exchange_integral_max` int(11) unsigned NOT NULL DEFAULT '0', `feed_invalid_time` int(11) unsigned NOT NULL DEFAULT '0', `egg_invalid_time` int(11) unsigned NOT NULL DEFAULT '0', `surprised_invalid_time` int(11) unsigned NOT NULL DEFAULT '0', `eat_experience` int(11) unsigned NOT NULL DEFAULT '0', `rate` decimal(10,2) unsigned NOT NULL DEFAULT '0.00', `advertisement_max` int(11) unsigned NOT NULL DEFAULT '1', `surprised_probability` int(11) unsigned NOT NULL DEFAULT '1', `shop` text, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_surprised` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `category` enum('优惠券','积分') NOT NULL DEFAULT '优惠券', `value` text, `probability` int(11) unsigned NOT NULL DEFAULT '0', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_task` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `logo` text, `title` varchar(64) NOT NULL DEFAULT '', `feed` int(11) unsigned NOT NULL DEFAULT '0', `order_feed` int(11) unsigned NOT NULL DEFAULT '0', `money_feed` decimal(10,2) unsigned NOT NULL DEFAULT '0.00', `goods_id` int(11) unsigned NOT NULL DEFAULT '0', `goods_feed` int(11) unsigned NOT NULL DEFAULT '0', `get_max` int(11) unsigned NOT NULL DEFAULT '0', `core` int(11) unsigned NOT NULL DEFAULT '0', `core_feed` int(11) unsigned NOT NULL DEFAULT '0', `member_level` int(11) unsigned NOT NULL DEFAULT '0', `member_level_feed` int(11) unsigned NOT NULL DEFAULT '0', `start_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', `end_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', `category` enum('签到','任务中心','购买商品','商城下单','会员领取') NOT NULL DEFAULT '签到', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_threshold` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `free` enum('1','0') DEFAULT NULL, `goods` int(11) unsigned NOT NULL DEFAULT '0', `level` int(11) unsigned NOT NULL DEFAULT '0', `consumption` enum('1','0') DEFAULT NULL, `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_user` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `name` varchar(64) NOT NULL DEFAULT '', `openid` varchar(56) DEFAULT NULL, `tofakeid` varchar(56) DEFAULT NULL, `follow` enum('0','1') NOT NULL DEFAULT '1', `consume` decimal(10,2) unsigned NOT NULL DEFAULT '0.00', `parent_id` int(11) unsigned NOT NULL DEFAULT '0', `portrait` text, `autograph` text, `sex` enum('男','女') NOT NULL DEFAULT '男', `birthday` date DEFAULT NULL, `distribution` enum('0','1') NOT NULL DEFAULT '1', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_user_friend` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `active_id` int(11) unsigned NOT NULL DEFAULT '0', `active_name` varchar(64) NOT NULL DEFAULT '', `active_openid` varchar(56) DEFAULT NULL, `active_tofakeid` varchar(56) DEFAULT NULL, `passive_id` int(11) unsigned NOT NULL DEFAULT '0', `passive_name` varchar(64) NOT NULL DEFAULT '', `passive_openid` varchar(56) DEFAULT NULL, `passive_tofakeid` varchar(56) DEFAULT NULL, `agree` enum('是','等待中','否') NOT NULL DEFAULT '等待中', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_user_prop` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `user_id` int(11) unsigned NOT NULL DEFAULT '0', `prop_id` int(11) unsigned NOT NULL DEFAULT '0', `total` int(11) unsigned NOT NULL DEFAULT '0', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_user_surprised` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `openid` varchar(64) DEFAULT NULL, `surprised_id` int(11) unsigned NOT NULL DEFAULT '0', `status` enum('是','否') NOT NULL DEFAULT '否', `use` enum('是','否') NOT NULL DEFAULT '否', `receive` enum('是','否') NOT NULL DEFAULT '否', `use_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_open_farm_user_task` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) unsigned NOT NULL DEFAULT '0', `openid` varchar(56) DEFAULT NULL, `task_id` int(11) unsigned NOT NULL DEFAULT '0', `rid` int(11) unsigned NOT NULL DEFAULT '0', `order_sum` int(11) unsigned NOT NULL DEFAULT '0', `order_money` decimal(10,2) unsigned NOT NULL DEFAULT '0.00', `goods_sum` int(11) unsigned NOT NULL DEFAULT '0', `status` enum('进行中','已完成','已领取') NOT NULL DEFAULT '进行中', `create_time` datetime NOT NULL DEFAULT '0000-00-00 00:00:00', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_abonus_bill` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `billno` varchar(100) DEFAULT '', `paytype` int(11) DEFAULT '0', `year` int(11) DEFAULT '0', `month` int(11) DEFAULT '0', `week` int(11) DEFAULT '0', `ordercount` int(11) DEFAULT '0', `ordermoney` decimal(10,2) DEFAULT '0.00', `paytime` int(11) DEFAULT '0', `aagentcount1` int(11) DEFAULT '0', `aagentcount2` int(11) DEFAULT '0', `aagentcount3` int(11) DEFAULT '0', `bonusmoney1` decimal(10,2) DEFAULT '0.00', `bonusmoney_send1` decimal(10,2) DEFAULT '0.00', `bonusmoney_pay1` decimal(10,2) DEFAULT '0.00', `bonusmoney2` decimal(10,2) DEFAULT '0.00', `bonusmoney_send2` decimal(10,2) DEFAULT '0.00', `bonusmoney_pay2` decimal(10,2) DEFAULT '0.00', `bonusmoney3` decimal(10,2) DEFAULT '0.00', `bonusmoney_send3` decimal(10,2) DEFAULT '0.00', `bonusmoney_pay3` decimal(10,2) DEFAULT '0.00', `createtime` int(11) DEFAULT '0', `status` tinyint(3) DEFAULT '0', `starttime` int(11) DEFAULT '0', `endtime` int(11) DEFAULT '0', `confirmtime` int(11) DEFAULT '0', `ceshi` int(11) DEFAULT NULL, PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_paytype` (`paytype`), KEY `idx_createtime` (`createtime`), KEY `idx_paytime` (`paytime`), KEY `idx_status` (`status`), KEY `idx_month` (`month`), KEY `idx_week` (`week`), KEY `idx_year` (`year`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_abonus_billo` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `billid` int(11) DEFAULT '0', `orderid` int(11) DEFAULT '0', `ordermoney` decimal(10,2) DEFAULT '0.00', PRIMARY KEY (`id`), KEY `idx_billid` (`billid`), KEY `idx_uniacid` (`uniacid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_abonus_billp` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `billid` int(11) DEFAULT '0', `openid` varchar(255) DEFAULT '', `payno` varchar(255) DEFAULT '', `paytype` tinyint(3) DEFAULT '0', `bonus1` decimal(10,4) DEFAULT '0.0000', `bonus2` decimal(10,4) DEFAULT '0.0000', `bonus3` decimal(10,4) DEFAULT '0.0000', `money1` decimal(10,2) DEFAULT '0.00', `realmoney1` decimal(10,2) DEFAULT '0.00', `paymoney1` decimal(10,2) DEFAULT '0.00', `money2` decimal(10,2) DEFAULT '0.00', `realmoney2` decimal(10,2) DEFAULT '0.00', `paymoney2` decimal(10,2) DEFAULT '0.00', `money3` decimal(10,2) DEFAULT '0.00', `realmoney3` decimal(10,2) DEFAULT '0.00', `paymoney3` decimal(10,2) DEFAULT '0.00', `chargemoney1` decimal(10,2) DEFAULT '0.00', `chargemoney2` decimal(10,2) DEFAULT '0.00', `chargemoney3` decimal(10,2) DEFAULT '0.00', `charge` decimal(10,2) DEFAULT '0.00', `status` tinyint(3) DEFAULT '0', `reason` varchar(255) DEFAULT '', `paytime` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_billid` (`billid`), KEY `idx_uniacid` (`uniacid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_abonus_level` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL, `levelname` varchar(50) DEFAULT '', `bonus1` decimal(10,4) DEFAULT '0.0000', `bonus2` decimal(10,4) DEFAULT '0.0000', `bonus3` decimal(10,4) DEFAULT '0.0000', `ordermoney` decimal(10,2) DEFAULT '0.00', `ordercount` int(11) DEFAULT '0', `bonusmoney` decimal(10,2) DEFAULT '0.00', `downcount` int(11) DEFAULT '0', `commissionmoney` decimal(10,2) DEFAULT '0.00', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_address_applyfor` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT NULL, `openid` varchar(11) DEFAULT NULL, `data` text, `orderid` int(11) DEFAULT NULL, `ordersn` varchar(255) DEFAULT NULL, `isdispose` tinyint(1) DEFAULT '0', `message` varchar(255) DEFAULT NULL, `createtime` int(11) DEFAULT NULL, `ispass` tinyint(1) DEFAULT '0', `isdelete` tinyint(4) DEFAULT '0', `isall` tinyint(4) DEFAULT '0', `old_address` text, `cycleid` int(11) DEFAULT NULL, PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_adv` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `advname` varchar(50) DEFAULT '', `link` varchar(255) DEFAULT '', `thumb` varchar(255) DEFAULT '', `displayorder` int(11) DEFAULT '0', `enabled` int(11) DEFAULT '0', `shopid` int(11) DEFAULT '0', `iswxapp` tinyint(1) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_enabled` (`enabled`), KEY `idx_displayorder` (`displayorder`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_af_supplier` ( `id` int(11) NOT NULL AUTO_INCREMENT, `openid` varchar(255) NOT NULL, `uniacid` int(11) NOT NULL, `realname` varchar(55) NOT NULL, `mobile` varchar(255) NOT NULL, `weixin` varchar(255) NOT NULL, `productname` varchar(255) NOT NULL, PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
