AULT '0', `article_rule_moneym2` decimal(10,2) NOT NULL DEFAULT '0.00', `article_readtime` int(11) DEFAULT '0', `article_areas` varchar(255) DEFAULT '', `article_endtime` int(11) DEFAULT '0', `article_hasendtime` tinyint(3) DEFAULT '0', `displayorder` int(11) DEFAULT '0', `article_advance` int(11) DEFAULT '0', `article_virtualadd` tinyint(3) DEFAULT '0', `article_visit` tinyint(3) DEFAULT '0', `article_visit_level` text, `article_visit_tip` varchar(500) DEFAULT '', PRIMARY KEY (`id`), KEY `idx_article_title` (`article_title`), KEY `idx_article_keyword` (`article_keyword`), KEY `idx_uniacid` (`uniacid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
