CREATE TABLE IF NOT EXISTS `ims_ewei_shop_system_company_article` ( `id` int(11) NOT NULL AUTO_INCREMENT, `title` varchar(255) DEFAULT '', `author` varchar(255) DEFAULT '', `thumb` varchar(255) DEFAULT '', `content` text, `createtime` int(11) DEFAULT '0', `displayorder` int(11) DEFAULT '0', `cate` int(11) DEFAULT '0', `status` tinyint(3) DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
