CREATE TABLE IF NOT EXISTS `ims_ewei_shop_upwxapp_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT NULL, `type` tinyint(2) DEFAULT '0', `version` varchar(20) DEFAULT NULL, `describe` varchar(50) DEFAULT NULL, `version_time` int(11) DEFAULT NULL, `is_goods` varchar(100) DEFAULT NULL, `is_live` tinyint(1) DEFAULT '0', `appid` varchar(50) DEFAULT NULL, `is_recharge` tinyint(1) DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_verifygoods` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT NULL, `openid` varchar(255) DEFAULT NULL, `orderid` int(11) DEFAULT NULL, `ordergoodsid` int(11) DEFAULT NULL, `storeid` int(11) DEFAULT NULL, `starttime` int(11) DEFAULT NULL, `limitdays` int(11) DEFAULT NULL, `limitnum` int(11) DEFAULT NULL, `used` tinyint(1) DEFAULT '0', `verifycode` varchar(20) DEFAULT NULL, `codeinvalidtime` int(11) DEFAULT NULL, `invalid` tinyint(1) DEFAULT '0', `getcard` tinyint(1) DEFAULT '0', `activecard` tinyint(1) DEFAULT '0', `cardcode` varchar(255) DEFAULT '', `limittype` tinyint(1) DEFAULT '0', `limitdate` int(11) DEFAULT '0', PRIMARY KEY (`id`), UNIQUE KEY `verifycode` (`verifycode`), KEY `idx_orderid` (`orderid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_verifygoods_log` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT NULL, `verifygoodsid` int(11) DEFAULT NULL, `salerid` int(11) DEFAULT NULL, `storeid` int(11) DEFAULT NULL, `verifynum` int(11) DEFAULT NULL, `verifydate` int(11) DEFAULT NULL, `remarks` varchar(255) DEFAULT NULL, PRIMARY KEY (`id`), KEY `uniacid` (`uniacid`), KEY `verifygoodsid` (`verifygoodsid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_verifyorder_log` ( `id` int(11) NOT NULL, `uniacid` int(11) DEFAULT NULL, `orderid` int(11) DEFAULT NULL, `salerid` int(11) DEFAULT NULL, `storeid` int(11) DEFAULT NULL, `verifytime` int(11) DEFAULT NULL, `verifyinfo` longtext, PRIMARY KEY (`id`), KEY `uniacid` (`uniacid`), KEY `orderid` (`orderid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_version` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uid` int(11) NOT NULL, `type` tinyint(3) NOT NULL DEFAULT '0', `uniacid` int(11) NOT NULL, `version` tinyint(3) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uid` (`uid`), KEY `idx_version` (`version`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_virtual_category` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `name` varchar(50) DEFAULT NULL, `merchid` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_virtual_data` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `typeid` int(11) NOT NULL DEFAULT '0', `pvalue` varchar(255) DEFAULT '', `fields` text NOT NULL, `openid` varchar(255) NOT NULL DEFAULT '', `usetime` int(11) NOT NULL DEFAULT '0', `orderid` int(11) DEFAULT '0', `ordersn` varchar(255) DEFAULT '', `price` decimal(10,2) DEFAULT '0.00', `merchid` int(11) DEFAULT '0', `createtime` int(11) NOT NULL, `is_top` tinyint(1) DEFAULT '0', `sort_time` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_typeid` (`typeid`), KEY `idx_usetime` (`usetime`), KEY `idx_orderid` (`orderid`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_virtual_send_log` ( `id` int(11) unsigned NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT '0', `openid` varchar(40) NOT NULL DEFAULT '', `orderid` tinyint(3) unsigned NOT NULL, `tag` varchar(20) NOT NULL, `default` varchar(2000) NOT NULL DEFAULT '', `cusdefault` varchar(2000) NOT NULL DEFAULT '', `url` varchar(128) NOT NULL DEFAULT '', `datas` varchar(2000) NOT NULL DEFAULT '', `appurl` varchar(128) NOT NULL DEFAULT '', `status` tinyint(4) NOT NULL DEFAULT '0', `sendtime` int(11) NOT NULL DEFAULT '0', `createtime` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_virtual_type` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `cate` int(11) DEFAULT '0', `title` varchar(255) NOT NULL DEFAULT '', `fields` text NOT NULL, `usedata` int(11) NOT NULL DEFAULT '0', `alldata` int(11) NOT NULL DEFAULT '0', `merchid` int(11) DEFAULT '0', `linktext` varchar(50) DEFAULT NULL, `linkurl` varchar(255) DEFAULT NULL, `recycled` int(11) NOT NULL DEFAULT '0', `description` text, PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_cate` (`cate`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxapp_bind` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `wxapp` int(11) NOT NULL, PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_wxapp` (`wxapp`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxapp_page` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `type` tinyint(2) NOT NULL DEFAULT '0', `name` varchar(255) DEFAULT NULL, `data` mediumtext, `createtime` int(11) NOT NULL DEFAULT '0', `lasttime` int(11) NOT NULL DEFAULT '0', `status` tinyint(1) NOT NULL DEFAULT '0', `isdefault` tinyint(1) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_type` (`type`), KEY `idx_status` (`status`), KEY `idx_isdefault` (`isdefault`) ) ENGINE=MyISAM AUTO_INCREMENT=2 DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxapp_poster` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `type` tinyint(3) NOT NULL DEFAULT '0', `title` varchar(255) DEFAULT NULL, `thumb` varchar(255) DEFAULT NULL, `bgimg` varchar(255) DEFAULT NULL, `data` text, `createtime` int(11) NOT NULL DEFAULT '0', `lastedittime` int(11) NOT NULL DEFAULT '0', `status` tinyint(3) NOT NULL DEFAULT '0', `displayorder` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_type` (`type`), KEY `idx_status` (`status`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxapp_startadv` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL, `status` tinyint(3) NOT NULL DEFAULT '0', `name` varchar(255) DEFAULT NULL, `data` text, `createtime` int(11) NOT NULL DEFAULT '0', `lastedittime` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_status` (`status`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxapp_subscribe` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL, `type` varchar(20) NOT NULL, `templateid` varchar(255) NOT NULL, `createtime` varchar(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxapp_tmessage` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL, `name` varchar(255) DEFAULT NULL, `templateid` varchar(50) DEFAULT '', `datas` text, `emphasis_keyword` int(11) NOT NULL DEFAULT '0', `status` tinyint(3) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_status` (`status`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxcard` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT NULL, `card_id` varchar(255) DEFAULT '0', `displayorder` int(11) DEFAULT NULL, `catid` int(11) DEFAULT NULL, `card_type` varchar(50) DEFAULT NULL, `logo_url` varchar(255) DEFAULT NULL, `wxlogourl` varchar(255) DEFAULT NULL, `brand_name` varchar(255) DEFAULT NULL, `code_type` varchar(255) DEFAULT NULL, `title` varchar(255) DEFAULT NULL, `color` varchar(50) DEFAULT NULL, `notice` varchar(50) DEFAULT NULL, `service_phone` varchar(50) DEFAULT NULL, `description` text, `datetype` varchar(50) DEFAULT NULL, `begin_timestamp` int(11) DEFAULT NULL, `end_timestamp` int(11) DEFAULT NULL, `fixed_term` int(11) DEFAULT NULL, `fixed_begin_term` int(11) DEFAULT NULL, `quantity` int(11) DEFAULT NULL, `total_quantity` varchar(255) DEFAULT NULL, `use_limit` int(11) DEFAULT NULL, `get_limit` int(11) DEFAULT NULL, `use_custom_code` tinyint(1) DEFAULT NULL, `bind_openid` tinyint(1) DEFAULT NULL, `can_share` tinyint(1) DEFAULT NULL, `can_give_friend` tinyint(1) DEFAULT NULL, `center_title` varchar(20) DEFAULT NULL, `center_sub_title` varchar(20) DEFAULT NULL, `center_url` varchar(255) DEFAULT NULL, `setcustom` tinyint(1) DEFAULT NULL, `custom_url_name` varchar(20) DEFAULT NULL, `custom_url_sub_title` varchar(20) DEFAULT NULL, `custom_url` varchar(255) DEFAULT NULL, `setpromotion` tinyint(1) DEFAULT NULL, `promotion_url_name` varchar(20) DEFAULT NULL, `promotion_url_sub_title` varchar(20) DEFAULT NULL, `promotion_url` varchar(255) DEFAULT NULL, `source` varchar(255) DEFAULT NULL, `can_use_with_other_discount` tinyint(1) DEFAULT NULL, `setabstract` tinyint(1) DEFAULT NULL, `abstract` varchar(50) DEFAULT NULL, `abstractimg` varchar(255) DEFAULT NULL, `icon_url_list` varchar(255) DEFAULT NULL, `accept_category` varchar(50) DEFAULT NULL, `reject_category` varchar(50) DEFAULT NULL, `least_cost` decimal(10,2) DEFAULT NULL, `reduce_cost` decimal(10,2) DEFAULT NULL, `discount` decimal(10,2) DEFAULT NULL, `limitgoodtype` tinyint(1) DEFAULT '0', `limitgoodcatetype` tinyint(1) unsigned DEFAULT '0', `limitgoodcateids` varchar(255) DEFAULT NULL, `limitgoodids` varchar(255) DEFAULT NULL, `limitdiscounttype` tinyint(1) unsigned DEFAULT '0', `merchid` int(11) DEFAULT '0', `gettype` tinyint(3) DEFAULT NULL, `islimitlevel` tinyint(1) DEFAULT '0', `limitmemberlevels` varchar(500) DEFAULT '', `limitagentlevels` varchar(500) DEFAULT '', `limitpartnerlevels` varchar(500) DEFAULT '', `limitaagentlevels` varchar(500) DEFAULT '', `settitlecolor` tinyint(1) DEFAULT '0', `titlecolor` varchar(10) DEFAULT '', `tagtitle` varchar(20) DEFAULT '', `use_condition` tinyint(1) DEFAULT '0', PRIMARY KEY (`id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxlive` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) NOT NULL DEFAULT '0', `room_id` int(11) NOT NULL DEFAULT '0', `name` varchar(50) NOT NULL DEFAULT '', `cover_img` varchar(255) NOT NULL DEFAULT '', `live_status` tinyint(3) NOT NULL DEFAULT '0', `local_live_status` tinyint(1) NOT NULL DEFAULT '0', `start_time` int(11) NOT NULL DEFAULT '0', `end_time` int(11) NOT NULL DEFAULT '0', `anchor_name` varchar(20) NOT NULL DEFAULT '', `anchor_img` varchar(255) NOT NULL DEFAULT '', `goods_json` text, `is_top` tinyint(1) NOT NULL DEFAULT '0', `is_recommend` tinyint(1) NOT NULL DEFAULT '0', `status` tinyint(4) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_start_time` (`start_time`), KEY `idx_end_time` (`end_time`), KEY `idx_is_top` (`is_top`), KEY `idx_is_recommend` (`is_recommend`), KEY `idx_local_live_status` (`local_live_status`), KEY `idx_status` (`status`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8;
CREATE TABLE IF NOT EXISTS `ims_ewei_shop_wxlive_back` ( `id` int(11) NOT NULL AUTO_INCREMENT, `uniacid` int(11) DEFAULT NULL, `live_id` int(11) NOT NULL, `room_id` int(11) NOT NULL, `expire_time` int(11) DEFAULT NULL, `create_time` int(11) DEFAULT NULL, `media_url` varchar(255) DEFAULT NULL, `show_times` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `idx_uniacid` (`uniacid`), KEY `idx_roomid` (`room_id`), KEY `idx_liveid` (`live_id`) ) ENGINE=MyISAM DEFAULT CHARSET=utf8;
