NSERT INTO ims_ewei_shop_task_type VALUES ('3','order_first','首次购物','在商城中首次下单，即可获得奖励，必须确认收货。','首次在商城中下单购物','0','','0','warning','0'); INSERT INTO ims_ewei_shop_task_type VALUES ('4','recharge_full','单笔充值满额','在商城中充值余额，单笔充值满额，即可获得奖励。','单笔充值满','1','元','0','success','1'); INSERT INTO ims_ewei_shop_task_type VALUES ('5','order_full','单笔满额','在商城中下单，单笔满额即可获得奖励，必须确认收货。','单笔订单满','1','元','0','success','1'); INSERT INTO ims_ewei_shop_task_type VALUES ('6','order_all','累计消费','在商城中购物消费，累计满额即可获得奖励，无需确认收货。','购物总消费额达到','1','元','0','success','0'); INSERT INTO ims_ewei_shop_task_type VALUES ('7','pyramid_money','分销佣金','只有分销商可接此任务。累计分销佣金满额，即可完成任务。','分销商获得佣金金额达','1','元','0','primary','0'); INSERT INTO ims_ewei_shop_task_type VALUES ('8','pyramid_num','下级人数','只有分销商可接此任务。累计下级人数达标，即可完成任务。','分销商推荐下级人数达','1','人','0','primary','0'); INSERT INTO ims_ewei_shop_task_type VALUES ('9','comment','商品好评','任意给一个商品五星好评，即可完成任务获得奖励。','给商品好评','0','','0','warning','0'); INSERT INTO ims_ewei_shop_task_type VALUES ('10','post','社区发帖','在社区中发表指定篇帖子，即可完成任务获得奖励。','在论坛中发表','1','篇帖子','0','warning','0'); INSERT INTO ims_ewei_shop_task_type VALUES ('11','goods','购买指定商品','购买指定商品后即可完成任务，必须确认收货。','购买指定商品','0','','1','info','0'); INSERT INTO ims_ewei_shop_task_type VALUES ('12','recharge_count','累计充值满额','在商城中充值余额，累计充值满额，即可获得奖励。','累计充值满','1','元','0','success','0'); INSERT INTO ims_ewei_shop_touch_loop_list VALUES ('1','1','5','dsadsdsa1','a:1:{i:0;s:51:\"images/1/2021/01/UFtdDT0zxG1yDNSFgljtlKZ9BXN1KX.jpg\";}','0','1610542973','1','1'); INSERT INTO ims_ewei_shop_wxapp_page VALUES ('1','1','2','首页','','1611054882','1611915379','1','1');

